1	package graph
2	
3	import (
4		v1 "k8s.io/api/core/v1"
5		"k8s.io/apimachinery/pkg/types"
6		"sigs.k8s.io/controller-runtime/pkg/client"
7	
8		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kinds"
9	)
10	
11	// A ReferencedService represents a Kubernetes Service that is referenced by a Route and the Gateways it belongs to.
12	// It does not contain the v1.Service object, because Services are resolved when building
13	// the dataplane.Configuration.
14	type ReferencedService struct {
15		// GatewayNsNames are all the Gateways that this Service indirectly attaches to through a Route.
16		GatewayNsNames map[types.NamespacedName]struct{}
17		// ExternalName holds the external service name for ExternalName type services.
18		ExternalName string
19		// Policies is a list of NGF Policies that target this Service.
20		Policies []*Policy
21		// IsExternalName indicates whether this Service is of type ExternalName.
22		IsExternalName bool
23	}
24	
25	func buildReferencedServices(
26		l7routes map[RouteKey]*L7Route,
27		l4Routes map[L4RouteKey]*L4Route,
28		gws map[types.NamespacedName]*Gateway,
29		services map[types.NamespacedName]*v1.Service,
30		listenerSets map[types.NamespacedName]*ListenerSet,
31	) map[types.NamespacedName]*ReferencedService {
32		referencedServices := make(map[types.NamespacedName]*ReferencedService)
33	
34		for gwNsName, gw := range gws {
35			if gw == nil {
36				continue
37			}
38	
39			processL7RoutesForGateway(l7routes, gw, gwNsName, referencedServices, services, listenerSets)
40			processL4RoutesForGateway(l4Routes, gw, gwNsName, referencedServices, services, listenerSets)
41		}
42	
43		if len(referencedServices) == 0 {
44			return nil
45		}
46	
47		return referencedServices
48	}
49	
50	// processL7RoutesForGateway processes all L7 routes that belong to the given gateway.
51	func processL7RoutesForGateway(
52		l7routes map[RouteKey]*L7Route,
53		gw *Gateway,
54		gwNsName types.NamespacedName,
55		referencedServices map[types.NamespacedName]*ReferencedService,
56		services map[types.NamespacedName]*v1.Service,
57		listenerSets map[types.NamespacedName]*ListenerSet,
58	) {
59		gwKey := client.ObjectKeyFromObject(gw.Source)
60	
61		for _, route := range l7routes {
62			if !route.Valid || !routeBelongsToGateway(route.ParentRefs, gwKey, listenerSets) {
63				continue
64			}
65	
66			// Process both valid and invalid BackendRefs as invalid ones still have referenced services
67			// we may want to track.
68			addServicesFromL7RouteRules(route.Spec.Rules, gwNsName, referencedServices, services)
69		}
70	}
71	
72	// processL4RoutesForGateway processes all L4 routes that belong to the given gateway.
73	func processL4RoutesForGateway(
74		l4Routes map[L4RouteKey]*L4Route,
75		gw *Gateway,
76		gwNsName types.NamespacedName,
77		referencedServices map[types.NamespacedName]*ReferencedService,
78		services map[types.NamespacedName]*v1.Service,
79		listenerSets map[types.NamespacedName]*ListenerSet,
80	) {
81		gwKey := client.ObjectKeyFromObject(gw.Source)
82	
83		for _, route := range l4Routes {
84			if !route.Valid || !routeBelongsToGateway(route.ParentRefs, gwKey, listenerSets) {
85				continue
86			}
87	
88			addServiceFromL4Route(route, gwNsName, referencedServices, services)
89		}
90	}
91	
92	// routeBelongsToGateway checks if a route belongs to the specified gateway.
93	// This includes checking if the route has a ListenerSet parentRef that belongs to the gateway.
94	func routeBelongsToGateway(
95		refs []ParentRef,
96		gwKey types.NamespacedName,
97		listenerSets map[types.NamespacedName]*ListenerSet,
98	) bool {
99		for _, ref := range refs {
100			switch ref.Kind {
101			case kinds.Gateway:
102				if ref.NamespacedName == gwKey {
103					return true
104				}
105			case kinds.ListenerSet:
106				if listenerSets[ref.NamespacedName] != nil &&
107					listenerSets[ref.NamespacedName].Gateway != nil &&
108					client.ObjectKeyFromObject(listenerSets[ref.NamespacedName].Gateway) == gwKey {
109					return true
110				}
111			}
112		}
113	
114		return false
115	}
116	
117	// addServiceFromL4Route adds services from an L4 route to the referenced services map.
118	// Supports multiple BackendRefs for TCPRoute/UDPRoute.
119	func addServiceFromL4Route(
120		route *L4Route,
121		gwNsName types.NamespacedName,
122		referencedServices map[types.NamespacedName]*ReferencedService,
123		services map[types.NamespacedName]*v1.Service,
124	) {
125		// Use helper method to get all backend references
126		backendRefs := route.Spec.GetBackendRefs()
127	
128		for _, br := range backendRefs {
129			svcNsName := br.SvcNsName
130			if svcNsName == (types.NamespacedName{}) {
131				continue
132			}
133	
134			ensureReferencedService(svcNsName, referencedServices, services)
135			referencedServices[svcNsName].GatewayNsNames[gwNsName] = struct{}{}
136		}
137	}
138	
139	// addServicesFromL7RouteRules adds services from L7 route rules to the referenced services map.
140	func addServicesFromL7RouteRules(
141		routeRules []RouteRule,
142		gwNsName types.NamespacedName,
143		referencedServices map[types.NamespacedName]*ReferencedService,
144		services map[types.NamespacedName]*v1.Service,
145	) {
146		for _, rule := range routeRules {
147			for _, ref := range rule.BackendRefs {
148				if ref.SvcNsName == (types.NamespacedName{}) {
149					continue
150				}
151	
152				ensureReferencedService(ref.SvcNsName, referencedServices, services)
153				referencedServices[ref.SvcNsName].GatewayNsNames[gwNsName] = struct{}{}
154			}
155		}
156	}
157	
158	// ensureReferencedService ensures a ReferencedService exists in the map for the given service.
159	func ensureReferencedService(
160		svcNsName types.NamespacedName,
161		referencedServices map[types.NamespacedName]*ReferencedService,
162		services map[types.NamespacedName]*v1.Service,
163	) {
164		if _, exists := referencedServices[svcNsName]; exists {
165			return
166		}
167	
168		isExternal, externalName := getServiceExternalNameInfo(svcNsName, services)
169		referencedServices[svcNsName] = &ReferencedService{
170			Policies:       nil,
171			GatewayNsNames: make(map[types.NamespacedName]struct{}),
172			IsExternalName: isExternal,
173			ExternalName:   externalName,
174		}
175	}
176	
177	// getServiceExternalNameInfo returns whether a service is an ExternalName service and its external name.
178	func getServiceExternalNameInfo(
179		svcNsName types.NamespacedName,
180		services map[types.NamespacedName]*v1.Service,
181	) (isExternal bool, externalName string) {
182		svc, exists := services[svcNsName]
183		if !exists || svc.Spec.Type != v1.ServiceTypeExternalName {
184			return false, ""
185		}
186	
187		return true, svc.Spec.ExternalName
188	}
