163	// newReferenceGrantResolver creates a new referenceGrantResolver.
164	func newReferenceGrantResolver(refGrants map[types.NamespacedName]*v1.ReferenceGrant) *referenceGrantResolver {
165		allowed := make(map[allowedReference]struct{})
166	
167		for nsname, grant := range refGrants {
168			for _, to := range grant.Spec.To {
169				for _, from := range grant.Spec.From {
170					toName := ""
171					if to.Name != nil {
172						toName = string(*to.Name)
173					}
174	
175					toGroup := string(to.Group)
176					if toGroup == "core" {
177						toGroup = ""
178					}
179	
180					ar := allowedReference{
181						to: toResource{
182							group:     toGroup,
183							kind:      string(to.Kind),
184							name:      toName,
185							namespace: nsname.Namespace,
186						},
187						from: fromResource{
188							group:     string(from.Group),
189							kind:      string(from.Kind),
190							namespace: string(from.Namespace),
191						},
192					}
193	
194					allowed[ar] = struct{}{}
195				}
196			}
197		}
198	
199		return &referenceGrantResolver{allowed: allowed}
200	}
201	
202	// refAllowed returns whether the reference from the fromResource to the toResource is allowed by a ReferenceGrant.
203	func (r *referenceGrantResolver) refAllowed(to toResource, from fromResource) bool {
204		specificKey := allowedReference{
205			to:   to,
206			from: from,
207		}
208	
209		// omit name field to check for ReferenceGrants that allow access to all resources
210		// of the particular kind in the namespace
211		allInNamespaceKey := allowedReference{
212			to: toResource{
213				group:     to.group,
214				kind:      to.kind,
215				namespace: to.namespace,
216			},
217			from: from,
218		}
219	
220		for _, key := range []allowedReference{specificKey, allInNamespaceKey} {
221			if _, ok := r.allowed[key]; ok {
222				return true
223			}
224		}
225	
226		return false
227	}
228	
229	// refAllowedFrom returns a closure function that takes a toResource parameter
230	// and checks if a reference from the specified fromResource to the given toResource is allowed.
231	func (r *referenceGrantResolver) refAllowedFrom(from fromResource) func(to toResource) bool {
232		return func(to toResource) bool {
233			return r.refAllowed(to, from)
234		}
235	}
