}

func toService(nsname types.NamespacedName) toResource {
	return toResource{
		kind:      kinds.Service,
		name:      nsname.Name,
		namespace: nsname.Namespace,
	}
}

func toInferencePool(nsname types.NamespacedName) toResource {
	return toResource{
		group:     inferenceAPIGroup,
		kind:      kinds.InferencePool,
		name:      nsname.Name,
		namespace: nsname.Namespace,
	}
}

func fromGateway(namespace string) fromResource {
	return fromResource{
		group:     v1.GroupName,
