	}
}

func fromHTTPRoute(namespace string) fromResource {
	return fromResource{
		group:     v1.GroupName,
		kind:      kinds.HTTPRoute,
		namespace: namespace,
	}
}

func fromGRPCRoute(namespace string) fromResource {
	return fromResource{
		group:     v1.GroupName,
		kind:      kinds.GRPCRoute,
		namespace: namespace,
	}
}

func fromTLSRoute(namespace string) fromResource {
	return fromResource{
		group:     v1.GroupName,
		kind:      kinds.TLSRoute,
		namespace: namespace,
	}
}

func fromTCPRoute(namespace string) fromResource {
	return fromResource{
		group:     v1.GroupName,
		kind:      kinds.TCPRoute,
		namespace: namespace,
	}
}

func fromUDPRoute(namespace string) fromResource {
	return fromResource{
		group:     v1.GroupName,
		kind:      kinds.UDPRoute,
		namespace: namespace,
	}
}

func fromListenerSet(namespace string) fromResource {
	return fromResource{
		group:     v1.GroupName,
		kind:      kinds.ListenerSet,
		namespace: namespace,
	}
}

const (
	ngfAPIGroup = "gateway.nginx.org"
	wafAPIGroup = "appprotect.f5.com"
